// PostRPCStreamBody sends a POST to the given service using a streaming request body.
// Caller must close the returned ReadCloser.
//
// Bodies of unknown length (e.g. io.MultiReader wrapping a pipe from a
// concurrent pack encoder, as used for receive-pack push paths) are
// spooled to a temp file so the request can be sent with an explicit
// Content-Length. Some servers — notably Cloudflare's git-over-HTTPS
// frontend — close the connection on chunked-transfer-encoded
// receive-pack uploads, matching upstream git's long-standing behaviour
// of buffering receive-pack request bodies. Spooling also lets Go's
// transport retry transient connection failures via req.GetBody.
//
// Bodies that already have a known length (*bytes.Reader, *bytes.Buffer,
// *strings.Reader) pass through unchanged — Go's transport sets
// Content-Length automatically for those types.
func (c *HTTPConn) PostRPCStreamBody(ctx context.Context, service string, body io.Reader, v2 bool, phase string) (io.ReadCloser, error) {
	reqURL := fmt.Sprintf("%s/%s", c.EndpointURL.String(), service)
	ctx = withHTTPTrace(ctx, "POST "+service)

	body, cleanup, err := spoolUnknownLengthBody(body)
	if err != nil {
		return nil, fmt.Errorf("spool request body: %w", err)
	}
	defer cleanup()

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, reqURL, body)
	if err != nil {
		return nil, fmt.Errorf("create RPC request: %w", err)
	}
	if spooled, ok := body.(*spooledBody); ok {
		req.ContentLength = spooled.size
		path := spooled.path
		req.GetBody = func() (io.ReadCloser, error) {
			return os.Open(path)
		}
	}
	req.Header.Set("Content-Type", fmt.Sprintf("application/x-%s-request", service))
	req.Header.Set("Accept", fmt.Sprintf("application/x-%s-result", service))
	req.Header.Set("User-Agent", capability.DefaultAgent())
	req.Header.Set(StatsPhaseHeader, phase)
	if v2 {
		req.Header.Set("Git-Protocol", GitProtocolV2)
	}
	ApplyAuth(req, c.Auth)

	if httpTraceEnabled() {
		dumpOutgoingRequest(req, "POST "+service)
	}

	res, err := c.HTTP.Do(req)
	if err != nil {
		return nil, fmt.Errorf("post RPC: %w", err)
	}
	if err := httpError(res); err != nil {
		_ = res.Body.Close()
		return nil, err
	}
	return res.Body, nil
}

// spooledBody is the temp-file-backed io.ReadCloser returned by
// spoolUnknownLengthBody. The fields are read by PostRPCStreamBody to
// wire up req.ContentLength and req.GetBody before the request is sent.
type spooledBody struct {
	io.ReadCloser
	path string
	size int64
}

// spoolUnknownLengthBody returns body unchanged when its length is
// already known to net/http (so Content-Length is set automatically),
// or a *spooledBody backed by a temp file otherwise. The returned
// cleanup is always non-nil and safe to call exactly once.
func spoolUnknownLengthBody(body io.Reader) (io.Reader, func(), error) {
	switch body.(type) {
	case *bytes.Reader, *bytes.Buffer, *strings.Reader:
		return body, func() {}, nil
	}

	f, err := os.CreateTemp("", "git-sync-rpc-*")
	if err != nil {
		return nil, func() {}, fmt.Errorf("create temp file: %w", err)
	}
	path := f.Name()
	cleanup := func() {
		_ = os.Remove(path)
	}
	size, err := io.Copy(f, body)
	if err != nil {
		_ = f.Close()
		cleanup()
		return nil, func() {}, fmt.Errorf("write request body to temp file: %w", err)
	}
	if _, err := f.Seek(0, io.SeekStart); err != nil {
		_ = f.Close()
		cleanup()
		return nil, func() {}, fmt.Errorf("rewind request body temp file: %w", err)
	}
	return &spooledBody{ReadCloser: f, path: path, size: size}, cleanup, nil
}

