// PostRPCStreamBody sends a POST to the given service using a streaming request body.
// Caller must close the returned ReadCloser.
//
// The body is sent as-is. Streaming bodies (io.MultiReader, io.PipeReader)
// produce a chunked request — that's the right shape for relay paths,
// where source pack bytes flow through to the target without buffering.
// Callers that need an explicit Content-Length (e.g. the materialized
// push path, which spools the full payload to a temp file to work around
// servers that reject chunked receive-pack uploads) pass a *SpooledBody
// instead, and PostRPCStreamBody sets req.ContentLength and req.GetBody
// from its fields so Go's transport can also auto-retry transient
// connection failures.
func (c *HTTPConn) PostRPCStreamBody(ctx context.Context, service string, body io.Reader, v2 bool, phase string) (io.ReadCloser, error) {
	reqURL := fmt.Sprintf("%s/%s", c.EndpointURL.String(), service)
	ctx = withHTTPTrace(ctx, "POST "+service)

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, reqURL, body)
	if err != nil {
		return nil, fmt.Errorf("create RPC request: %w", err)
	}
	if spooled, ok := body.(*SpooledBody); ok {
		req.ContentLength = spooled.size
		path := spooled.path
		req.GetBody = func() (io.ReadCloser, error) {
			return os.Open(path)
		}
	}
	req.Header.Set("Content-Type", fmt.Sprintf("application/x-%s-request", service))
	req.Header.Set("Accept", fmt.Sprintf("application/x-%s-result", service))
	req.Header.Set("User-Agent", capability.DefaultAgent())
	req.Header.Set(StatsPhaseHeader, phase)
	if v2 {
		req.Header.Set("Git-Protocol", GitProtocolV2)
	}
	ApplyAuth(req, c.Auth)

	if httpTraceEnabled() {
		dumpOutgoingRequest(req, "POST "+service)
	}

	res, err := c.HTTP.Do(req)
	if err != nil {
		return nil, fmt.Errorf("post RPC: %w", err)
	}
	if err := httpError(res); err != nil {
		_ = res.Body.Close()
		return nil, err
	}
	return res.Body, nil
}

// SpooledBody is a temp-file-backed request body with a known length.
// PostRPCStreamBody type-asserts on it and sets req.ContentLength /
// req.GetBody so the request goes out with an explicit length (no
// chunked encoding) and is replayable on transient connection failures.
//
// Used by the materialized push path, where the full payload is known
// in advance (the closure walk already requires a local store, so
// spooling on upload doesn't change the strategy's fundamental shape).
// Relay paths intentionally don't use this — they stream source bytes
// straight through, which is the whole point of the relay shape.
type SpooledBody struct {
	io.ReadCloser
	path string
	size int64
}

// NewSpooledBody creates a temp file, writes write(f) into it, rewinds
// it, and returns a SpooledBody plus a cleanup that removes the temp
// file. The cleanup is always non-nil; call it (typically via defer)
// regardless of error.
func NewSpooledBody(write func(io.Writer) error) (*SpooledBody, func(), error) {
	f, err := os.CreateTemp("", "git-sync-rpc-*")
	if err != nil {
		return nil, func() {}, fmt.Errorf("create temp file: %w", err)
	}
	path := f.Name()
	cleanup := func() {
		_ = f.Close()
		_ = os.Remove(path)
	}
	if err := write(f); err != nil {
		cleanup()
		return nil, func() {}, err
	}
	size, err := f.Seek(0, io.SeekCurrent)
	if err != nil {
		cleanup()
		return nil, func() {}, fmt.Errorf("get spooled body size: %w", err)
	}
	if _, err := f.Seek(0, io.SeekStart); err != nil {
		cleanup()
		return nil, func() {}, fmt.Errorf("rewind spooled body: %w", err)
	}
	return &SpooledBody{ReadCloser: f, path: path, size: size}, cleanup, nil
}

